+    #[test]
+    fn client_debug_redacts_auth() {
+        let rt = fcp_async_core::runtime::block_on_sync(async {
+            AwsClient::new(
+                AwsAuth {
+                    access_key_id: "AKIAIOSFODNN7EXAMPLE".into(),
+                    secret_access_key: "wJalrXUtnFEMI/K7MDENG".into(),
+                    session_token: None,
+                },
+                "us-east-1",
+                HttpRetryConfig::default(),
+                None,
+                None,
+                None,
+                None,
+            )
+            .await
+            .unwrap()
+        })
+        .unwrap();
+
+        let debug = format!("{rt:?}");
+        assert!(debug.contains("[REDACTED]"));
+        assert!(!debug.contains("AKIAIOSFODNN7EXAMPLE"));
+        assert!(!debug.contains("wJalrXUtnFEMI"));
+    }
+
+    #[test]
+    fn secretless_detection() {
+        let rt = fcp_async_core::runtime::block_on_sync(async {
+            AwsClient::new(
+                AwsAuth {
+                    access_key_id: String::new(),
+                    secret_access_key: String::new(),
+                    session_token: None,
+                },
+                "us-east-1",
+                HttpRetryConfig::default(),
+                None,
+                None,
+                None,
+                None,
+            )
+            .await
+            .unwrap()
+        })
+        .unwrap();
+        assert!(rt.is_secretless());
+
+        let rt2 = fcp_async_core::runtime::block_on_sync(async {
+            AwsClient::new(
+                AwsAuth {
+                    access_key_id: "AKID".into(),
+                    secret_access_key: "secret".into(),
+                    session_token: None,
+                },
+                "us-east-1",
+                HttpRetryConfig::default(),
+                None,
+                None,
+                None,
+                None,
+            )
+            .await
+            .unwrap()
+        })
+        .unwrap();
+        assert!(!rt2.is_secretless());
+    }
+
